// 7-segment counter controlled by potentiometer
// Pot on A0 (14): 0-1023 → 0-9 display

// Segment pins
const int segA = 2;
const int segB = 3;
const int segC = 4;
const int segD = 5;
const int segE = 6;
const int segF = 7;
const int segG = 8;

// Pot pin
const int potPin = 14;  // A0

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
}

void displayDigit(int digit) {
  // Define segment patterns for digits 0-9
  // Each digit: a, b, c, d, e, f, g (1 = on, 0 = off)

  int a, b, c, d, e, f, g;

  if (digit == 0) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0;
  } else if (digit == 1) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 2) {
    a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1;
  } else if (digit == 3) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1;
  } else if (digit == 4) {
    a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1;
  } else if (digit == 5) {
    a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else if (digit == 6) {
    a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 7) {
    a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0;
  } else if (digit == 8) {
    a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1;
  } else if (digit == 9) {
    a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1;
  } else {
    a = 0; b = 0; c = 0; d = 0; e = 0; f = 0; g = 0;
  }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

void loop() {
  // Read potentiometer (0-1023)
  int potValue = analogRead(potPin);

  // Map to digit 0-9
  int digit = potValue / 102;  // 1024 / 10 = ~102.4
  if (digit > 9) {
    digit = 9;
  }

  // Display the digit
  displayDigit(digit);

  delay(50);  // Smooth reading
}

